using System.ComponentModel;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";
var topic   = args.Length > 0 ? string.Join(' ', args)
            : PromptUser("Enter a research topic: ");

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: set the OPENAI_API_KEY environment variable.");
    return 1;
}

Console.WriteLine($"\n🔬 Research Agent — topic: \"{topic}\"\n");

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();
var webSearch = new WebSearchTool();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ---------------------------------------------------------------------------
// Chat client
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()   // auto-invoke tools
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

var history = new List<ChatMessage>
{
    new(ChatRole.System,
        """
        You are a research assistant. Your job is to thoroughly research the
        user's topic by searching the web multiple times to gather diverse
        information. After each useful search, save key findings as notes using
        the note-taking tool.

        Follow this workflow:
        1. Break the topic into 2-4 sub-questions.
        2. Search the web for each sub-question (call search_the_web).
        3. Save important facts, data, and quotes as notes (call add_note).
        4. When you have enough material, retrieve all notes (call get_notes)
           and write a well-structured summary with sections and citations.
        5. Present the final summary to the user.
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}"),
};

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
var response = await client.GetResponseAsync(history, chatOptions);

Console.WriteLine("\n────────────────────────────────────────");
Console.WriteLine(" RESEARCH SUMMARY");
Console.WriteLine("────────────────────────────────────────\n");
Console.WriteLine(response.Text);
Console.WriteLine();

return 0;

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------
static string PromptUser(string prompt)
{
    Console.Write(prompt);
    return Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

// ---------------------------------------------------------------------------
// Web search tool — uses DuckDuckGo HTML and scrapes result snippets
// ---------------------------------------------------------------------------
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    [Description("Search the web for a query and return a list of result snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍 Searching: {query}");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            var results = ParseResults(html);
            if (results.Count == 0)
                return "No results found.";

            return JsonSerializer.Serialize(results,
                new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseResults(string html)
    {
        var results = new List<SearchResult>();
        // DuckDuckGo HTML results sit inside <a class="result__a"> and
        // <a class="result__snippet"> elements.
        var titlePattern  = new Regex(
            @"<a[^>]+class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline);
        var snippetPattern = new Regex(
            @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline);
        var hrefPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""", RegexOptions.Singleline);

        var titles   = titlePattern.Matches(html);
        var snippets = snippetPattern.Matches(html);
        var hrefs    = hrefPattern.Matches(html);

        var count = Math.Min(titles.Count, Math.Min(snippets.Count, hrefs.Count));
        count = Math.Min(count, 5); // top 5

        for (var i = 0; i < count; i++)
        {
            results.Add(new SearchResult
            {
                Title   = StripHtml(titles[i].Groups[1].Value),
                Snippet = StripHtml(snippets[i].Groups[1].Value),
                Url     = hrefs[i].Groups[1].Value,
            });
        }

        return results;
    }

    private static string StripHtml(string s) =>
        Regex.Replace(s, "<.*?>", "").Trim();

    private sealed class SearchResult
    {
        public string Title   { get; set; } = "";
        public string Snippet { get; set; } = "";
        public string Url     { get; set; } = "";
    }
}

// ---------------------------------------------------------------------------
// Note-taking tool — in-memory notebook the agent uses to collect findings
// ---------------------------------------------------------------------------
sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record important facts, "
               + "data points, or quotes discovered during research.")]
    public string AddNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note saved (total: {_notes.Count}).";
    }

    [Description("Retrieve all saved research notes so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

